import React, { useEffect, useRef } from 'react';
import { ArrowRight, ChevronDown } from 'lucide-react';
import { PERSONAL_INFO } from '../constants';
import { motion, useScroll, useTransform, Variants } from 'framer-motion';
import { useTheme } from '../context/ThemeContext';

// --- Pixel Art Engine & Assets ---

interface Entity {
  id: number;
  type: 'sheep' | 'goose' | 'chicken';
  x: number;
  y: number;
  dir: 1 | -1;
  speed: number;
  frameOffset: number;
}

const PixelBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const { theme } = useTheme();

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let time = 0;
    const pixelScale = 4;

    // Game State
    const animals: Entity[] = [];
    // Spawn animals
    for(let i=0; i<3; i++) animals.push({ id: Math.random(), type: 'sheep', x: 20 + Math.random() * 100, y: Math.random() * 20, dir: Math.random() > 0.5 ? 1 : -1, speed: 0.1 + Math.random() * 0.1, frameOffset: Math.random() * 100 });
    for(let i=0; i<2; i++) animals.push({ id: Math.random(), type: 'goose', x: 150 + Math.random() * 100, y: Math.random() * 20, dir: Math.random() > 0.5 ? 1 : -1, speed: 0.2 + Math.random() * 0.2, frameOffset: Math.random() * 100 });
    for(let i=0; i<3; i++) animals.push({ id: Math.random(), type: 'chicken', x: 80 + Math.random() * 60, y: Math.random() * 15, dir: Math.random() > 0.5 ? 1 : -1, speed: 0.3 + Math.random() * 0.3, frameOffset: Math.random() * 100 });

    const drawPixelRect = (x: number, y: number, w: number, h: number, color: string) => {
      ctx.fillStyle = color;
      ctx.fillRect(Math.floor(x) * pixelScale, Math.floor(y) * pixelScale, w * pixelScale, h * pixelScale);
    };

    const drawTree = (x: number, y: number) => {
      // Trunk
      drawPixelRect(x + 3, y - 10, 2, 10, '#8B4513');
      // Leaves
      const leafColor = theme === 'dark' ? '#1e3a1e' : '#228B22';
      drawPixelRect(x, y - 20, 8, 10, leafColor);
      drawPixelRect(x + 1, y - 24, 6, 4, leafColor);
      drawPixelRect(x + 2, y - 26, 4, 2, leafColor);
    };

    const drawPizzaOven = (x: number, y: number, t: number) => {
      // Base
      drawPixelRect(x, y - 12, 14, 12, '#7a7a7a');
      // Dome
      drawPixelRect(x + 1, y - 14, 12, 2, '#7a7a7a');
      drawPixelRect(x + 3, y - 15, 8, 1, '#7a7a7a');
      // Opening
      drawPixelRect(x + 4, y - 8, 6, 6, '#2a2a2a');
      // Chimney
      drawPixelRect(x + 8, y - 18, 3, 4, '#5a5a5a');
      drawPixelRect(x + 7, y - 20, 5, 2, '#4a4a4a');

      // Fire Animation
      if (Math.floor(t / 10) % 2 === 0) {
        drawPixelRect(x + 5, y - 6, 4, 4, '#FF4500'); // Red
        drawPixelRect(x + 6, y - 5, 2, 2, '#FFD700'); // Yellow
      } else {
        drawPixelRect(x + 5, y - 5, 4, 3, '#FF8C00'); // Orange
        drawPixelRect(x + 6, y - 6, 2, 2, '#FFFF00'); // Bright Yellow
      }

      // Smoke
      const smokeY = (t * 0.2) % 30;
      if (smokeY < 20) {
          drawPixelRect(x + 9 + Math.sin(t * 0.05) * 2, y - 22 - smokeY, 2, 2, 'rgba(200,200,200,0.5)');
      }
    };

    const drawGuy = (x: number, y: number, t: number) => {
      // Body (Sitting)
      drawPixelRect(x + 2, y - 10, 4, 6, '#3b82f6'); // Shirt
      drawPixelRect(x + 2, y - 4, 6, 2, '#1e293b'); // Legs Horizontal
      drawPixelRect(x + 7, y - 2, 1, 2, '#1e293b'); // Legs Vertical

      // Head
      drawPixelRect(x + 2, y - 15, 4, 5, '#ffccaa'); // Skin
      drawPixelRect(x + 2, y - 16, 4, 2, '#451a03'); // Hair

      // Laptop
      drawPixelRect(x + 6, y - 8, 5, 1, '#94a3b8'); // Base
      drawPixelRect(x + 6, y - 13, 1, 5, '#94a3b8'); // Screen Back
      drawPixelRect(x + 6.5, y - 12.5, 0.5, 4, '#e0f2fe'); // Screen Glow

      // Arms/Typing
      const handY = Math.floor(t / 10) % 2 === 0 ? -7 : -8;
      drawPixelRect(x + 4, y + handY, 3, 1, '#ffccaa');
    };

    const drawAnimal = (entity: Entity, t: number) => {
      const bounce = Math.sin((t + entity.frameOffset) * 0.2) > 0 ? 1 : 0;
      const ay = entity.y + bounce;
      const faceX = entity.dir === 1 ? entity.x + (entity.type === 'sheep' ? 6 : entity.type === 'goose' ? 4 : 3) : entity.x - 1;

      if (entity.type === 'sheep') {
        // Body
        drawPixelRect(entity.x, ay - 6, 8, 5, '#f1f5f9');
        // Legs
        if (bounce === 0) {
            drawPixelRect(entity.x + 1, ay - 1, 1, 2, '#0f172a');
            drawPixelRect(entity.x + 6, ay - 1, 1, 2, '#0f172a');
        }
        // Head
        drawPixelRect(entity.dir === 1 ? entity.x + 6 : entity.x - 2, ay - 7, 3, 3, '#0f172a');
      } 
      else if (entity.type === 'goose') {
        // Body
        drawPixelRect(entity.x, ay - 4, 5, 3, '#ffffff');
        // Neck
        drawPixelRect(entity.dir === 1 ? entity.x + 4 : entity.x, ay - 8, 1, 4, '#ffffff');
        // Beak
        drawPixelRect(entity.dir === 1 ? entity.x + 5 : entity.x - 1, ay - 7, 1, 1, '#f97316');
      }
      else if (entity.type === 'chicken') {
        // Body
        drawPixelRect(entity.x, ay - 3, 3, 2, '#9a3412');
        // Head
        drawPixelRect(entity.dir === 1 ? entity.x + 2 : entity.x - 1, ay - 5, 2, 2, '#9a3412');
        // Comb
        drawPixelRect(entity.dir === 1 ? entity.x + 2 : entity.x, ay - 6, 1, 1, '#dc2626');
      }
    };

    const render = () => {
      time++;

      // Responsive Canvas sizing
      if (canvas.width !== canvas.clientWidth || canvas.height !== canvas.clientHeight) {
        canvas.width = canvas.clientWidth;
        canvas.height = canvas.clientHeight;
        ctx.imageSmoothingEnabled = false;
      }

      const w = Math.ceil(canvas.width / pixelScale);
      const h = Math.ceil(canvas.height / pixelScale);
      const groundY = Math.floor(h * 0.65);

      // --- Draw Background ---

      // Sky
      const skyGradient = ctx.createLinearGradient(0, 0, 0, canvas.height);
      if (theme === 'dark') {
          skyGradient.addColorStop(0, '#0f172a');
          skyGradient.addColorStop(1, '#1e1b4b');
      } else {
          skyGradient.addColorStop(0, '#7dd3fc');
          skyGradient.addColorStop(1, '#bae6fd');
      }
      ctx.fillStyle = skyGradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Clouds
      ctx.fillStyle = theme === 'dark' ? 'rgba(255,255,255,0.1)' : 'rgba(255,255,255,0.6)';
      const cloudSpeed = 0.05;
      const c1x = (time * cloudSpeed) % (w + 40) - 20;
      const c2x = ((time * cloudSpeed * 0.8) + 100) % (w + 40) - 20;

      drawPixelRect(c1x, 10, 15, 6, ctx.fillStyle as string);
      drawPixelRect(c1x + 5, 6, 8, 4, ctx.fillStyle as string);

      drawPixelRect(c2x, 20, 20, 5, ctx.fillStyle as string);
      drawPixelRect(c2x + 4, 16, 10, 4, ctx.fillStyle as string);

      // Ground (Grass)
      const grassColor = theme === 'dark' ? '#14532d' : '#4ade80';
      const dirtColor = theme === 'dark' ? '#3f6212' : '#22c55e';

      ctx.fillStyle = grassColor;
      ctx.fillRect(0, groundY * pixelScale, canvas.width, (h - groundY) * pixelScale);

      // Grass texture detail (random noise but deterministic based on position)
      for (let i = 0; i < w; i += 4) {
          if ((i * 13 + 7) % 5 === 0) {
              drawPixelRect(i, groundY + 2 + ((i*7)%10), 1, 1, dirtColor);
          }
      }

      // Background Trees
      drawTree(20, groundY);
      drawTree(w - 20, groundY);
      drawTree(w * 0.15, groundY - 2);
      drawTree(w * 0.8, groundY - 5);

      // --- Draw Interactive Elements ---

      // Pizza Oven (Right side)
      const ovenX = Math.floor(w * 0.75);
      drawPizzaOven(ovenX, groundY + 15, time);

      // The Guy (Left-ish Center)
      const guyX = Math.floor(w * 0.3);
      drawGuy(guyX, groundY + 20, time);

      // Animals
      animals.forEach(animal => {
        // Move
        if (Math.random() < 0.01) animal.dir *= -1;
        animal.x += animal.speed * animal.dir;

        // Boundaries
        if (animal.x < 0) { animal.x = 0; animal.dir = 1; }
        if (animal.x > w - 10) { animal.x = w - 10; animal.dir = -1; }

        // Y-Sort approximation: Draw lower y first? 
        // We just draw them relative to ground. 
        // Visual depth: lower on screen = closer.
        const animalY = groundY + 10 + animal.y;

        drawAnimal(animal, time);
      });

      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => cancelAnimationFrame(animationFrameId);
  }, [theme]);

  return (
    <div className="absolute inset-0 w-full h-full overflow-hidden">
      <canvas ref={canvasRef} className="w-full h-full block image-pixelated" style={{ imageRendering: 'pixelated' }} />
      {/* Vignette Overlay for text readability */}
      <div className="absolute inset-0 bg-gradient-to-b from-secondary/80 via-secondary/40 to-secondary/90 backdrop-blur-[1px]"></div>
    </div>
  );
};

