import React, { useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Home from './components/Home';
import BlogPostPage from './components/BlogPostPage';
import Footer from './components/Footer';
import { ThemeProvider } from './context/ThemeContext';
import Lenis from 'lenis';

const App: React.FC = () => {
  useEffect(() => {
    const lenis = new Lenis({
      duration: 1.2,
      easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
      direction: 'vertical',
      gestureDirection: 'vertical',
      smooth: true,
      mouseMultiplier: 1,
      smoothTouch: false,
      touchMultiplier: 2,
    });

    function raf(time: number) {
      lenis.raf(time);
      requestAnimationFrame(raf);
    }

    requestAnimationFrame(raf);

    // Modified anchor handling for router compatibility
    const handleAnchorClick = (e: MouseEvent) => {
      const target = e.target as HTMLElement;
      const anchor = target.closest('a');

      if (anchor) {
        const href = anchor.getAttribute('href');
        if (href && href.startsWith('#')) {
          // If we are on the home page, scroll normally.
          // If we are not on home, we shouldn't intercept, let Router handle navigation (if using HashLink)
          // But here simple anchor scrolling only works on single page.
          if (window.location.pathname === '/' || window.location.pathname === '') {
             e.preventDefault();
             if (href === '#') {
               lenis.scrollTo(0);
               return;
             }
             try {
               const element = document.querySelector(href);
               if (element) {
                 lenis.scrollTo(element);
               }
             } catch (err) {
               console.warn(`Invalid selector skipped: ${href}`);
             }
          }
        }
      }
    };

    document.addEventListener('click', handleAnchorClick);

    return () => {
      lenis.destroy();
      document.removeEventListener('click', handleAnchorClick);
    };
  }, []);

  return (
    <ThemeProvider>
      <Router>
        <div className="relative min-h-screen text-text-primary selection:bg-accent selection:text-white transition-colors duration-300">
          <div className="fixed inset-0 -z-50 gradient-bg transition-colors duration-500"></div>

          <Navbar />
          <main>
            <Routes>
              <Route path="/" element={<Home />} />
              <Route path="/blog/:id" element={<BlogPostPage />} />
            </Routes>
          </main>
          <Footer />
        </div>
      </Router>
    </ThemeProvider>
  );
};

export default App;

