// --- Pixel Art Engine & Assets ---

interface Entity {
  id: number;
  type: 'sheep' | 'goose' | 'chicken';
  x: number;
  y: number; // Offset from ground Y
  dir: 1 | -1;
  speed: number;
  frameOffset: number;
}

interface Star {
  x: number;
  y: number;
  size: number;
  twinkleSpeed: number;
  phase: number;
}

const PixelBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const { theme } = useTheme();

