  const starsRef = useRef<Star[]>([]);

  // Initialize stars once
  useEffect(() => {
    if (starsRef.current.length === 0) {
      for (let i = 0; i < 50; i++) {
        starsRef.current.push({
          x: Math.random(), // Relative 0-1
          y: Math.random() * 0.6, // Top 60% of screen
